  ('dietitian-moex-05543', 'dietitian', 'dietitian-moex-109-da9d23a3', 'sub-dietitian-06', NULL, 'single_choice', '有關低溫保藏食物，下列敘述何者正確？', '["冷藏溫度（0~7℃）能抑制病原菌的生長，因此冷藏食品沒有食物中毒的疑慮", "冷凍溫度（-18℃）殺滅微生物的效率類似商業滅菌", "冷凍時，食物中冰晶的形成會破壞微生物細胞", "由於低溫能降低化學反應及微生物活動，因此冷藏蔬果溫度接近0℃最好"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:41+00:00", "source_pdf_sha1": "3d37ea7f3a54", "answer_pdf_sha1": "66acddad3c29", "source_family": "moex-gov-tw", "moex": {"exam_code": "109110", "c": "103", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "食品衛生與安全", "year": "109", "exam_name": "109年第二次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試、109年專技人員高等考試法醫師、語言治療師、聽力...", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
